    hasCreated.current = true;

    const create = async () => {
      try {
        const documentId = await createDocument({ sessionId });
        router.replace(`/app/documents/${documentId}`);
      } catch (error) {
        console.error('Failed to create document:', error);
        router.replace('/app/documents');
